VALUES
  ('social-worker-moex-07020', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '某一社會福利機構舉辦勸募活動募得三千萬元，依據公益勸募條例，其勸募活動之必要支出最高金額為？', '["三百萬元", "三百一十萬元", "三百二十萬元", "三百三十萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "e76ae2116f13", "answer_pdf_sha1": "3ff5687a9119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07021', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據特殊境遇家庭扶助條例，相關福利給付標準，下列何者錯誤？', '["緊急生活扶助者，按當年度低收入戶每人每月最低生活費用標準一點五倍核發", "子女生活津貼之核發標準，每一名子女或孫子女每月補助當年度最低工資之十分之一，每年申請一次", "教育補助就讀大專院校減免學雜費百分之六十", "無力負擔訴訟費用者，得申請法律訴訟補助。其標準最高金額以新臺幣五萬元為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "e76ae2116f13", "answer_pdf_sha1": "3ff5687a9119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07022', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列有關公益勸募相關規定，何者錯誤？', '["適用範圍為基於公益目的，為政治或團體或個人，募集財物或接受捐贈之勸募行為", "勸募團體為公立學校、行政法人或財團法人等", "勸募辦理情形及收支決算應於規定期限內送設立、立案或監督之機關備查", "援外或國際人道救援屬勸募之用途之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "e76ae2116f13", "answer_pdf_sha1": "3ff5687a9119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07023', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問下列有關我國社會保險制度之最低加保年齡，何者錯誤？', '["國民年金保險為25歲", "勞工保險為15歲", "農民保險為20歲", "公教人員保險沒有最低加保年齡之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "e76ae2116f13", "answer_pdf_sha1": "3ff5687a9119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07024', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問公教人員保險法第5條規定，公教保險如有虧損，下列何者為其處理方式？', '["全數由國庫審核撥補", "應調整費率挹注", "由公益彩券盈餘貼補20％，不足數由國庫貼補", "民國88年5月30日以前之虧損由財政部審核撥補；以後的虧損，應調整費率挹注"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "e76ae2116f13", "answer_pdf_sha1": "3ff5687a9119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07025', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問在我國現行各類社會保險制度中，那一種社會保險制度已實施預繳一定期間之保險費措施？', '["農民健康保險", "國民年金保險", "就業保險", "公教人員保險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "e76ae2116f13", "answer_pdf_sha1": "3ff5687a9119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07026', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問下列有關國民年金法中遺屬年金給付相關規定，何者錯誤？', '["遺屬年金給付請領條件中的配偶應年滿五十五歲，且婚姻關係存續一年以上者", "配偶未滿五十五歲，但無謀生能力者不在此限", "父母及祖父母應年滿六十歲，且每月工作收入未超過其領取遺屬年金給付時之月投保金額", "養子女亦涵括到遺屬範圍，但須有收養關係六個月以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "e76ae2116f13", "answer_pdf_sha1": "3ff5687a9119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07027', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問下列有關我國社會保險制度老年（養老）給付型態，何者正確？', '["國民年金保險之老年給付採一次給付及年金給付併行制", "勞工保險之老年給付採一次給付及年金給付併行制", "公教保險之老年給付採年金給付制", "農民保險之老年給付採年金給付制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "e76ae2116f13", "answer_pdf_sha1": "3ff5687a9119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07028', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問下列有關國民年金法中老年基本保證年金相關規定，何者正確？', '["老年基本保證年金之給付來源，來自保險費", "老年基本保證年金之請領人年滿六十五歲，在國內設有戶籍者，且最近二年內每年居住國內超過一百 八十三日者", "最近一年個人綜合所得總額未超過新臺幣五十萬元者", "短期羈押或拘禁不在此限，仍可繼續請領"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "e76ae2116f13", "answer_pdf_sha1": "3ff5687a9119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07029', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問勞工退休金條例有關退休金專戶之提繳及領取相關規定，下列何者錯誤？', '["雇主每月負擔之勞工退休金提繳率，不得低於工資之百分之六", "勞工僅能在每月工資百分之六範圍提繳，不得增加", "退休金領取之方式計有月退休金及一次退休金兩種方式", "勞工退休金運用收益，不得低於當地銀行二年定期存款利率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "e76ae2116f13", "answer_pdf_sha1": "3ff5687a9119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
